// Extended dhātu list — composes the top-25 (in dhatus.js) with three
// per-frequency-range part files generated by parallel agents to reach
// the Khoomeik top-192 (~86.1% verb-token coverage).
//
// Used by decodeHelper.js classifyByStem for vocabulary-backed verb
// detection — the more dhātus we have, the more verbs the engine can
// confirm on top of the regex-based pass.
//
// Each part file exports DHATUS_PART_N: array of dhātu entries with
// at minimum {id, devanagari, presentStem, pada, gana} — enough for
// the cross-check; richer fields (futureStem, perfect3sg, gitaOccurrences)
// are filled in only on the top-25 today.
//
// Coverage status:
//   - dhatus.js DHATUS:        ranks 1–25   (rich data)
//   - _dhatus_part2.js:        ranks 26–100  (75 entries)
//   - _dhatus_part3.js:        ranks 101–150 (50 entries)
//   - _dhatus_part4.js:        ranks 151–192 (42 entries)
// Total: 192 dhātus (~86.1% verb-token coverage of the DCS corpus).
//
// Audit and tighten the bulk-generated entries' presentStems over time.

import { DHATUS_TOP25 } from './dhatus.js';
import { DHATUS_PART_2 } from './_dhatus_part2.js';
import { DHATUS_PART_3 } from './_dhatus_part3.js';
import { DHATUS_PART_4 } from './_dhatus_part4.js';

export const DHATUS_EXTENDED = [
  ...DHATUS_TOP25,
  ...DHATUS_PART_2,
  ...DHATUS_PART_3,
  ...DHATUS_PART_4,
];
